<div class="text-center mb-5 pt-4"><h2 class="fw-bold">New Password</h2><p class="text-secondary">Set the new password for your account so you can login and access all features.</p></div>
<form class="mx-auto" style="max-width: 450px;"><div class="mb-4"><label for="newPassword" class="form-label">Enter new password</label><input type="password" class="form-control form-control-lg" id="newPassword"></div><div class="mb-4"><label for="confirmPassword" class="form-label">Confirm password</label><input type="password" class="form-control form-control-lg" id="confirmPassword"></div><button type="submit" class="btn btn-dark w-100 btn-lg mt-3" style="background-color: #2c3e50;">UPDATE PASSWORD</button></form>
